public void selectionChanged()
{
    SalesTable      salesTable, salesTableLoc ;
    PurchAgreementId    purchAgreementId;
    next selectionChanged();

    purchAgreementId = SalesAgreementHeader::find(salesAgreementHeader.RecId).ETG_PurchAgreementIdTP;

    this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage,GeneratePurchAgreement), false);

    this.listPage().actionPaneControlEnabled(formControlStr(SalesAgreementListPage, ButtonPurchAgreementTP),false);


    if(purchAgreementId)
    {
        this.listPage().actionPaneControlEnabled(formControlStr(SalesAgreementListPage, ButtonPurchAgreementTP),true);
    }
    else
    {
        this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage,GeneratePurchAgreement), true);
    }

    if(salesAgreementHeader.ETG_TradingStatusSales == ETG_TradingStatus::Released)
    {
        this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage,BtnNewReleaseOrder), false);
    }

    this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, ButtonConfirmationETG), salesAgreementHeader.ETG_TradingStatusSales == ETG_TradingStatus::None);

    if(ETGACFParameters::find().EnableAbruptTerminationAgreement == NoYes::Yes)
    {
        if(salesAgreementHeader.AgreementState == AgreementState::ETGTerminated || salesAgreementHeader.AgreementState == AgreementState::ETGForceClosed)
        {
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, BtnNewReleaseOrder), false);
        }
        else
        {
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, BtnNewReleaseOrder), true);
        }
    }
    if(ETGACFParameters::find().EnableSalesAgreementWorkflow == NoYes::Yes)
    {
        //NS, DLT  5/15/2025 Conformation button and release order button enable and disable conditions
        if(salesAgreementHeader.ETGWorkflowStatus == VersioningDocumentState::Approved && salesAgreementHeader.AgreementState == AgreementState::OnHold )
        {
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, ButtonConfirmationETG), true);
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, BtnNewReleaseOrder), false);
            //this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, ETG_ShippingInstructions), true);
        }
        else if (salesAgreementHeader.ETGWorkflowStatus == VersioningDocumentState::Approved && salesAgreementHeader.AgreementState == AgreementState::Effective )
        {
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, ButtonConfirmationETG), false);
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, BtnNewReleaseOrder), true);
           // this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, ETG_ShippingInstructions), false);
        }
        else if (salesAgreementHeader.ETGWorkflowStatus == VersioningDocumentState::Draft && salesAgreementHeader.AgreementState == AgreementState::OnHold )
        {
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, ButtonConfirmationETG), false);
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, BtnNewReleaseOrder), false);
        }
        else if (salesAgreementHeader.ETGWorkflowStatus == VersioningDocumentState::InReview && salesAgreementHeader.AgreementState == AgreementState::OnHold )
        {
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, ButtonConfirmationETG), false);
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, BtnNewReleaseOrder), false);
        }
        else if (salesAgreementHeader.ETGWorkflowStatus == VersioningDocumentState::Rejected && salesAgreementHeader.AgreementState == AgreementState::OnHold )
        {
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, ButtonConfirmationETG), false);
            this.listPage().actionPaneControlEnabled(formcontrolstr(SalesAgreementListPage, BtnNewReleaseOrder), false);
        }
        //NS, DLT  5/15/2025 Conformation button and release order button enable and disable conditions
    }

    //CS - Abhinav - Enable ETGProFormaInvoiceCanada control based on parameter boolean
    this.listPage().actionPaneControlVisible(formcontrolstr(SalesAgreementListPage, ETGProFormaInvoiceCanada), ETGCanadaParameters::find().EnableProformInvoiceGenerate);
    //CE
}
